export type AppData = {
  menu: Array<{
    name: string;
    href: string;
    items?: Array<{
      name: string;
      href: string;
    }>;
  }>;
  categories: Array<{
    name: string;
    href: string;
    icon: string;
  }>;
  drafts: Array<{
    name: string;
    href: string;
    image: string;
    price: {
      amount: number;
      ctaLink: string;
    };
    longDescription: string;
    keyFeatures: string[];
    idealFor: string[];
    Note?: string;
    keyDifferentiators: string[];
    tableOfContents: string[];
    disclaimer: string;
  }>;
};

export async function getAppData(): Promise<AppData> {
  const res = await fetch(
    "https://api.jsonsilo.com/86f0a608-3d0c-4568-8715-fa806fead848",
    {
      headers: {
        "X-SILO-KEY": "h6c3CUJGoukxhhV9bgaESGXZNfcHkRLwWwFX8hlY2V",
        "Content-Type": "application/json",
      },
      // Revalidate every 60 seconds
      next: { revalidate: 60 },
    }
  );

  if (!res.ok) {
    throw new Error("Failed to fetch data");
  }

  return res.json();
}
